import sqlite3
import os
import re
import hashlib
import time
from flask import Flask, render_template, request, jsonify, session, redirect, url_for, abort
from urllib.parse import unquote
from config import Config

app = Flask(__name__)
app.config.from_object(Config)

def get_db():
    db = sqlite3.connect(Config.DATABASE_PATH)
    db.row_factory = sqlite3.Row
    return db

def aegis_v8_shield(payload):
    if not payload:
        return "ts"

    # Layer 1: Strict Charset Restriction
    # Only alphanumeric and underscores allowed. All SQL syntax must be hex-encoded.
    if not re.match(r'^[a-zA-Z0-9_]*$', payload):
        return None

    # Layer 2: Hardened Recursive Keyword Removal
    # Strips keywords before translation to prevent basic bypasses
    keywords = ["SELECT", "FROM", "WHERE", "UNION", "ALL", "AND", "OR", "CASE", "WHEN", "THEN", "ELSE", "END", "GLOB", "SUBSTR", "ORDER", "BY"]
    sanitized = payload
    while True:
        upper_s = sanitized.upper()
        found_any = False
        for k in keywords:
            if k in upper_s:
                idx = upper_s.find(k)
                sanitized = sanitized[:idx] + sanitized[idx+len(k):]
                found_any = True
                break
        if not found_any:
            break
    return sanitized

def legacy_translation_engine(payload):
    # The legacy engine uses a specific offset for obfuscation.
    # Pattern: _x[HEX]_ translated to chr(int(HEX, 16) - 2)
    if payload.count('_x') > 80:
        return "ts"
    try:
        return re.sub(r'_x([0-9a-fA-F]{2})_', lambda m: chr(int(m.group(1), 16) - 2), payload)
    except Exception:
        return "ts"

def structural_integrity_check(payload):
    # Layer 3: Post-Translation WAF (Non-Recursive)
    # This WAF runs AFTER hex decoding. It is non-recursive, requiring nested bypasses.
    keywords = ["SELECT", "FROM", "WHERE", "UNION", "JOIN", "GROUP", "BY"]
    # Blacklist common extraction functions to force creative alternatives
    forbidden_funcs = ["SUBSTR", "LENGTH", "HEX", "ASCII", "UNICODE", "CHAR", "INSTR"]

    upper_p = payload.upper()

    # Function check
    if any(f in upper_p for f in forbidden_funcs):
        return False

    # Keyword stripping (one-pass only)
    for k in keywords:
        payload = re.sub(re.escape(k), '', payload, flags=re.IGNORECASE)

    return payload

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        db = get_db()
        user = db.execute('SELECT * FROM users WHERE username = ? AND password = ?', (username, password)).fetchone()
        if user:
            session['user'] = user['username']
            return redirect(url_for('dashboard'))
        return render_template('login.html', error="Invalid credentials")
    return render_template('login.html')

@app.route('/api/v3.1/telemetry/metrics')
def calibration_api():
    if 'user' not in session:
        return jsonify({"status": "error", "message": "Unauthorized"}), 401

    # Layer 4: Rolling Temporal Signature
    # X-Orbital-Signature: SHA256(user + floor(time/30) + salt)
    sig = request.headers.get('X-Orbital-Signature', '')
    protocol = request.headers.get('X-Orbital-Protocol', '')

    bucket = str(int(time.time() // 30))
    expected_sig = hashlib.sha256((session['user'] + bucket + "AETHERIS_2024").encode()).hexdigest()

    if protocol != "v3.1":
        return jsonify({"status": "error", "message": "Protocol mismatch: v3.1 required"}), 400
    if sig != expected_sig:
        return jsonify({"status": "error", "message": "Invalid security signature for current time window"}), 403

    sort_param = request.args.get('sort', 'ts')

    # WAF Step 1: Normalized input validation
    pre_waf = aegis_v8_shield(unquote(sort_param))
    if pre_waf is None:
        return jsonify({"status": "error", "message": "Security Violation: Layer 1/2"}), 403

    # Translation Step: Hex decoding with offset
    translated = legacy_translation_engine(pre_waf)

    # WAF Step 2: Post-translation structural check
    final_sort = structural_integrity_check(translated)
    if not final_sort:
        return jsonify({"status": "error", "message": "Security Violation: Layer 3 (Function Blacklist)"}), 403

    try:
        db = get_db()
        # Vulnerability: concatenated ORDER BY for blind SQLi extraction
        query = f"SELECT ts, val FROM telemetry WHERE s_id = 1 ORDER BY {final_sort} LIMIT 2"
        cursor = db.execute(query)
        results = [dict(row) for row in cursor.fetchall()]

        # Standardized output to force focus on row ordering (blind signal)
        return jsonify({"status": "success", "data": results})
    except Exception as e:
        # Generic error message to prevent leak via error details
        return jsonify({"status": "error", "message": "E500: Processing Fault"}), 500

@app.route('/dashboard')
def dashboard():
    if 'user' not in session:
        return redirect(url_for('login'))
    return render_template('dashboard.html')

@app.route('/logout')
def logout():
    session.pop('user', None)
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

