{% extends 'base.html' %}
{% block content %}
<h1>Research Dashboard</h1>
<!-- NOTICE: Protocol v3.1 active. Legacy translation requires 0x02 rotational shift. -->
<!-- Signature auth: HEX(SHA256(USER + BUCKET_30S + 'AETHERIS_2024')) -->
<div class='card'>
    <h3>Active Satellites</h3>
    <ul>
        <li>Aetheris-Alpha (ID: 1) - Operational</li>
        <li>Gaea-Prime (ID: 2) - Maintenance</li>
    </ul>
</div>
<div class='card'>
    <h3>Telemetry Logs</h3>
    <button class='btn' onclick='fetchCalibration()'>Run Calibration Check</button>
    <div id='log-output' style='margin-top: 15px; font-family: monospace; font-size: 0.8rem; white-space: pre-wrap;'></div>
</div>
<script>
    async function fetchCalibration() {
        const user = '{{ session.user }}';
        const bucket = Math.floor(Date.now() / 30000);
        const msg = new TextEncoder().encode(user + bucket + 'AETHERIS_2024');
        const hashBuffer = await crypto.subtle.digest('SHA-256', msg);
        const hashArray = Array.from(new Uint8Array(hashBuffer));
        const signature = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');

        fetch('/api/v3.1/telemetry/metrics?sort=ts', {
            headers: {
                'X-Orbital-Signature': signature,
                'X-Orbital-Protocol': 'v3.1'
            }
        })
        .then(r => r.json())
        .then(d => {
            document.getElementById('log-output').innerText = JSON.stringify(d, null, 2);
        });
    }
</script>
{% endblock %}
